program LipDecide;

uses
  Math;

const
  PI = 3.1415926535;
  MAXPTS = 100;
  NLIC = 15;

type
  POINTRANGE = 1..MAXPTS;
  LICRANGE = 1..NLIC;
  NPOINTS = 2..MAXPTS;
  NPTYPE = 3..MAXPTS;
  CONNECTORS = (NOTUSED, ORR, ANDD);
  NUMQUADS = 1..3;
  COORDINATE = array[POINTRANGE] of real;
  CMATRIX = array[LICRANGE, LICRANGE] of CONNECTORS;
  BMATRIX = array[LICRANGE, LICRANGE] of boolean;
  VECTOR = array[LICRANGE] of boolean;
  COMPTYPE = (LT, EQ, GT);

var
  X: COORDINATE;
  Y: COORDINATE;
  NUMPOINTS: NPOINTS;
  PARAMETERS: record
    LENGTH1: real;
    RADIUS1: real;
    EPSILON: real;
    AREA1: real;
    Q_PTS: NPOINTS;
    QUADS: NUMQUADS;
    DIST: real;
    N_PTS: NPTYPE;
    K_PTS: POINTRANGE;
    A_PTS: POINTRANGE;
    B_PTS: POINTRANGE;
    C_PTS: POINTRANGE;
    D_PTS: POINTRANGE;
    E_PTS: POINTRANGE;
    F_PTS: POINTRANGE;
    G_PTS: POINTRANGE;
    LENGTH2: real;
    RADIUS2: real;
    AREA2: real;
  end;
  LCM: CMATRIX;
  PUM: BMATRIX;
  CMV: VECTOR;
  FUV: VECTOR;
  LAUNCH: boolean;

  InputBuf: AnsiString;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  scale, eps, diff: real;
begin
  scale := Abs(A);
  if Abs(B) > scale then
    scale := Abs(B);
  if scale = 0.0 then
  begin
    REALCOMPARE := EQ;
    Exit;
  end;

  eps := 0.5e-5 * scale;
  diff := A - B;
  if diff > eps then
    REALCOMPARE := GT
  else if diff < -eps then
    REALCOMPARE := LT
  else
    REALCOMPARE := EQ;
end;

function SqrR(x: real): real;
begin
  SqrR := x * x;
end;

function Dist2D(x1, y1, x2, y2: real): real;
begin
  Dist2D := Sqrt(SqrR(x2 - x1) + SqrR(y2 - y1));
end;

function TriangleArea(x1, y1, x2, y2, x3, y3: real): real;
begin
  TriangleArea := 0.5 * Abs((x2 - x1) * (y3 - y1) - (x3 - x1) * (y2 - y1));
end;

function MinEnclosingRadius3(x1, y1, x2, y2, x3, y3: real): real;
var
  area, d12, d23, d13, mx: real;
begin
  area := TriangleArea(x1, y1, x2, y2, x3, y3);
  d12 := Dist2D(x1, y1, x2, y2);
  d23 := Dist2D(x2, y2, x3, y3);
  d13 := Dist2D(x1, y1, x3, y3);
  if REALCOMPARE(area, 0.0) = EQ then
  begin
    mx := d12;
    if REALCOMPARE(d23, mx) = GT then mx := d23;
    if REALCOMPARE(d13, mx) = GT then mx := d13;
    MinEnclosingRadius3 := mx / 2.0;
  end
  else
    MinEnclosingRadius3 := (d12 * d23 * d13) / (4.0 * area);
end;

function CannotFitCircleR(x1, y1, x2, y2, x3, y3, rad: real): boolean;
begin
  CannotFitCircleR := REALCOMPARE(MinEnclosingRadius3(x1, y1, x2, y2, x3, y3), rad) = GT;
end;

function CanFitCircleR(x1, y1, x2, y2, x3, y3, rad: real): boolean;
var
  r: real;
begin
  r := MinEnclosingRadius3(x1, y1, x2, y2, x3, y3);
  CanFitCircleR := (REALCOMPARE(r, rad) = LT) or (REALCOMPARE(r, rad) = EQ);
end;

function AngleAtVertex(x1, y1, xv, yv, x3, y3: real): real;
var
  v1x, v1y, v2x, v2y, len1, len2, dotp: real;
begin
  if (REALCOMPARE(x1, xv) = EQ) and (REALCOMPARE(y1, yv) = EQ) then
  begin
    AngleAtVertex := -1.0;
    Exit;
  end;
  if (REALCOMPARE(x3, xv) = EQ) and (REALCOMPARE(y3, yv) = EQ) then
  begin
    AngleAtVertex := -1.0;
    Exit;
  end;
  v1x := x1 - xv;
  v1y := y1 - yv;
  v2x := x3 - xv;
  v2y := y3 - yv;
  len1 := Sqrt(SqrR(v1x) + SqrR(v1y));
  len2 := Sqrt(SqrR(v2x) + SqrR(v2y));
  if (REALCOMPARE(len1, 0.0) = EQ) or (REALCOMPARE(len2, 0.0) = EQ) then
  begin
    AngleAtVertex := -1.0;
    Exit;
  end;
  dotp := (v1x * v2x + v1y * v2y) / (len1 * len2);
  if REALCOMPARE(dotp, 1.0) = GT then
    dotp := 1.0
  else if REALCOMPARE(dotp, -1.0) = LT then
    dotp := -1.0;
  AngleAtVertex := ArcCos(dotp);
end;

function AngleLicMet(x1, y1, xv, yv, x3, y3: real): boolean;
var
  ang, lo, hi: real;
begin
  ang := AngleAtVertex(x1, y1, xv, yv, x3, y3);
  if REALCOMPARE(ang, 0.0) = LT then
  begin
    AngleLicMet := false;
    Exit;
  end;
  lo := PI - PARAMETERS.EPSILON;
  hi := PI + PARAMETERS.EPSILON;
  AngleLicMet := (REALCOMPARE(ang, lo) = LT) or (REALCOMPARE(ang, hi) = GT);
end;

function Quadrant(px, py: real): integer;
begin
  if (REALCOMPARE(px, 0.0) = EQ) and (REALCOMPARE(py, 0.0) = EQ) then
    Quadrant := 1
  else if (REALCOMPARE(py, 0.0) = EQ) and (REALCOMPARE(px, 0.0) = GT) then
    Quadrant := 1
  else if (REALCOMPARE(px, 0.0) = EQ) and (REALCOMPARE(py, 0.0) = GT) then
    Quadrant := 1
  else if (REALCOMPARE(px, 0.0) = EQ) and (REALCOMPARE(py, 0.0) = LT) then
    Quadrant := 3
  else if (REALCOMPARE(py, 0.0) = EQ) and (REALCOMPARE(px, 0.0) = LT) then
    Quadrant := 2
  else if REALCOMPARE(px, 0.0) = GT then
  begin
    if REALCOMPARE(py, 0.0) = GT then
      Quadrant := 1
    else if REALCOMPARE(py, 0.0) = LT then
      Quadrant := 4
    else
      Quadrant := 1;
  end
  else
  begin
    if REALCOMPARE(py, 0.0) = GT then
      Quadrant := 2
    else if REALCOMPARE(py, 0.0) = LT then
      Quadrant := 3
    else
      Quadrant := 2;
  end;
end;

function PointLineDist(px, py, x1, y1, x2, y2: real): real;
var
  num, den: real;
begin
  den := Sqrt(SqrR(y2 - y1) + SqrR(x2 - x1));
  if REALCOMPARE(den, 0.0) = EQ then
    PointLineDist := Dist2D(px, py, x1, y1)
  else
  begin
    num := Abs((y2 - y1) * px - (x2 - x1) * py + x2 * y1 - y2 * x1);
    PointLineDist := num / den;
  end;
end;

function Lic1: boolean;
var
  i: integer;
  d: real;
begin
  Lic1 := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    d := Dist2D(X[i], Y[i], X[i + 1], Y[i + 1]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
    begin
      Lic1 := true;
      Exit;
    end;
  end;
end;

function Lic2: boolean;
var
  i: integer;
begin
  Lic2 := false;
  for i := 1 to NUMPOINTS - 2 do
    if CannotFitCircleR(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2], PARAMETERS.RADIUS1) then
    begin
      Lic2 := true;
      Exit;
    end;
end;

function Lic3: boolean;
var
  i: integer;
begin
  Lic3 := false;
  for i := 1 to NUMPOINTS - 2 do
    if AngleLicMet(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]) then
    begin
      Lic3 := true;
      Exit;
    end;
end;

function Lic4: boolean;
var
  i: integer;
  a: real;
begin
  Lic4 := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    a := TriangleArea(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
    if REALCOMPARE(a, PARAMETERS.AREA1) = GT then
    begin
      Lic4 := true;
      Exit;
    end;
  end;
end;

function Lic5: boolean;
var
  i, j, q, cnt: integer;
  seen: array[1..4] of boolean;
begin
  Lic5 := false;
  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    for q := 1 to 4 do
      seen[q] := false;
    cnt := 0;
    for j := 0 to PARAMETERS.Q_PTS - 1 do
    begin
      q := Quadrant(X[i + j], Y[i + j]);
      if not seen[q] then
      begin
        seen[q] := true;
        Inc(cnt);
      end;
    end;
    if cnt > PARAMETERS.QUADS then
    begin
      Lic5 := true;
      Exit;
    end;
  end;
end;

function Lic6: boolean;
var
  i: integer;
begin
  Lic6 := false;
  for i := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(X[i + 1] - X[i], 0.0) = LT then
    begin
      Lic6 := true;
      Exit;
    end;
end;

function Lic7: boolean;
var
  i, j, last: integer;
  d, mx: real;
begin
  Lic7 := false;
  if NUMPOINTS < 3 then
    Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    last := i + PARAMETERS.N_PTS - 1;
    mx := 0.0;
    if (REALCOMPARE(X[i], X[last]) = EQ) and (REALCOMPARE(Y[i], Y[last]) = EQ) then
    begin
      for j := i + 1 to last - 1 do
      begin
        d := Dist2D(X[j], Y[j], X[i], Y[i]);
        if REALCOMPARE(d, mx) = GT then
          mx := d;
      end;
    end
    else
    begin
      for j := i + 1 to last - 1 do
      begin
        d := PointLineDist(X[j], Y[j], X[i], Y[i], X[last], Y[last]);
        if REALCOMPARE(d, mx) = GT then
          mx := d;
      end;
    end;
    if REALCOMPARE(mx, PARAMETERS.DIST) = GT then
    begin
      Lic7 := true;
      Exit;
    end;
  end;
end;

function Lic8: boolean;
var
  i, j: integer;
  d: real;
begin
  Lic8 := false;
  if NUMPOINTS < 3 then
    Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    j := i + PARAMETERS.K_PTS + 1;
    d := Dist2D(X[i], Y[i], X[j], Y[j]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
    begin
      Lic8 := true;
      Exit;
    end;
  end;
end;

function Lic9: boolean;
var
  i, j, k: integer;
begin
  Lic9 := false;
  if NUMPOINTS < 5 then
    Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    if CannotFitCircleR(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS1) then
    begin
      Lic9 := true;
      Exit;
    end;
  end;
end;

function Lic10: boolean;
var
  i, j, k: integer;
begin
  Lic10 := false;
  if NUMPOINTS < 5 then
    Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
  begin
    j := i + PARAMETERS.C_PTS + 1;
    k := j + PARAMETERS.D_PTS + 1;
    if AngleLicMet(X[i], Y[i], X[j], Y[j], X[k], Y[k]) then
    begin
      Lic10 := true;
      Exit;
    end;
  end;
end;

function Lic11: boolean;
var
  i, j, k: integer;
  a: real;
begin
  Lic11 := false;
  if NUMPOINTS < 5 then
    Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    a := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if REALCOMPARE(a, PARAMETERS.AREA1) = GT then
    begin
      Lic11 := true;
      Exit;
    end;
  end;
end;

function Lic12: boolean;
var
  i, j: integer;
begin
  Lic12 := false;
  if NUMPOINTS < 3 then
    Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
  begin
    j := i + PARAMETERS.G_PTS + 1;
    if REALCOMPARE(X[j] - X[i], 0.0) = LT then
    begin
      Lic12 := true;
      Exit;
    end;
  end;
end;

function Lic13: boolean;
var
  i, j: integer;
  d: real;
  gtFound, ltFound: boolean;
begin
  Lic13 := false;
  if NUMPOINTS < 3 then
    Exit;
  gtFound := false;
  ltFound := false;
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    j := i + PARAMETERS.K_PTS + 1;
    d := Dist2D(X[i], Y[i], X[j], Y[j]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
      gtFound := true;
    if REALCOMPARE(d, PARAMETERS.LENGTH2) = LT then
      ltFound := true;
    if gtFound and ltFound then
    begin
      Lic13 := true;
      Exit;
    end;
  end;
end;

function Lic14: boolean;
var
  i, j, k: integer;
  notFit, fit: boolean;
begin
  Lic14 := false;
  if NUMPOINTS < 5 then
    Exit;
  notFit := false;
  fit := false;
  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    if CannotFitCircleR(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS1) then
      notFit := true;
    if CanFitCircleR(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS2) then
      fit := true;
    if notFit and fit then
    begin
      Lic14 := true;
      Exit;
    end;
  end;
end;

function Lic15: boolean;
var
  i, j, k: integer;
  a: real;
  gtFound, ltFound: boolean;
begin
  Lic15 := false;
  if NUMPOINTS < 5 then
    Exit;
  gtFound := false;
  ltFound := false;
  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    a := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if REALCOMPARE(a, PARAMETERS.AREA1) = GT then
      gtFound := true;
    if REALCOMPARE(a, PARAMETERS.AREA2) = LT then
      ltFound := true;
    if gtFound and ltFound then
    begin
      Lic15 := true;
      Exit;
    end;
  end;
end;

procedure ComputeCMV;
begin
  CMV[1] := Lic1;
  CMV[2] := Lic2;
  CMV[3] := Lic3;
  CMV[4] := Lic4;
  CMV[5] := Lic5;
  CMV[6] := Lic6;
  CMV[7] := Lic7;
  CMV[8] := Lic8;
  CMV[9] := Lic9;
  CMV[10] := Lic10;
  CMV[11] := Lic11;
  CMV[12] := Lic12;
  CMV[13] := Lic13;
  CMV[14] := Lic14;
  CMV[15] := Lic15;
end;

procedure ComputePUMOffDiag;
var
  i, j: integer;
begin
  for i := 1 to NLIC do
    for j := 1 to NLIC do
      if i <> j then
        case LCM[i, j] of
          NOTUSED: PUM[i, j] := true;
          ANDD: PUM[i, j] := CMV[i] and CMV[j];
          ORR: PUM[i, j] := CMV[i] or CMV[j];
        end;
end;

procedure ComputeFUV;
var
  i, j: integer;
  allTrue: boolean;
begin
  for i := 1 to NLIC do
  begin
    if not PUM[i, i] then
      FUV[i] := true
    else
    begin
      allTrue := true;
      for j := 1 to NLIC do
        if not PUM[i, j] then
        begin
          allTrue := false;
          Break;
        end;
      FUV[i] := allTrue;
    end;
  end;
end;

procedure ComputeLaunch;
var
  i: integer;
begin
  LAUNCH := true;
  for i := 1 to NLIC do
    if not FUV[i] then
    begin
      LAUNCH := false;
      Exit;
    end;
end;

procedure DECIDE;
begin
  ComputeCMV;
  ComputePUMOffDiag;
  ComputeFUV;
  ComputeLaunch;
end;

{ JSON parsing helpers }

function SkipWs(var p: integer): boolean;
begin
  while (p <= Length(InputBuf)) and (InputBuf[p] in [' ', #9, #10, #13, ',', ':']) do
    Inc(p);
  SkipWs := p <= Length(InputBuf);
end;

function ParseNumber(var p: integer; out v: real): boolean;
var
  start: integer;
  s: string;
  code: integer;
begin
  SkipWs(p);
  start := p;
  if (p <= Length(InputBuf)) and (InputBuf[p] = '-') then
    Inc(p);
  while (p <= Length(InputBuf)) and (InputBuf[p] in ['0'..'9', '.', 'e', 'E', '+', '-']) do
    Inc(p);
  s := Copy(InputBuf, start, p - start);
  Val(s, v, code);
  ParseNumber := code = 0;
end;

function ParseInt(var p: integer; out v: integer): boolean;
var
  r: real;
begin
  ParseInt := ParseNumber(p, r);
  v := Trunc(r);
end;

function ParseBool(var p: integer; out v: boolean): boolean;
begin
  ParseBool := false;
  SkipWs(p);
  if (p + 3 <= Length(InputBuf)) and (Copy(InputBuf, p, 4) = 'true') then
  begin
    v := true;
    Inc(p, 4);
    ParseBool := true;
    Exit;
  end;
  if (p + 4 <= Length(InputBuf)) and (Copy(InputBuf, p, 5) = 'false') then
  begin
    v := false;
    Inc(p, 5);
    ParseBool := true;
    Exit;
  end;
end;

function FindKey(const key: string; startPos: integer): integer;
var
  q: string;
  at: integer;
begin
  q := '"' + key + '"';
  at := Pos(q, InputBuf);
  if (at = 0) or (at < startPos) then
    FindKey := 0
  else
    FindKey := at + Length(q);
end;

function ParseStringToken(var p: integer; out tok: string): boolean;
var
  start: integer;
begin
  SkipWs(p);
  if (p > Length(InputBuf)) or (InputBuf[p] <> '"') then
  begin
    ParseStringToken := false;
    Exit;
  end;
  Inc(p);
  start := p;
  while (p <= Length(InputBuf)) and (InputBuf[p] <> '"') do
    Inc(p);
  tok := Copy(InputBuf, start, p - start);
  if (p <= Length(InputBuf)) and (InputBuf[p] = '"') then
    Inc(p);
  ParseStringToken := true;
end;

procedure ParseRealArray(const key: string; var arr: COORDINATE; count: integer);
var
  pos, p, i: integer;
  v: real;
begin
  pos := FindKey(key, 1);
  if pos = 0 then
    Exit;
  p := pos;
  SkipWs(p);
  if (p <= Length(InputBuf)) and (InputBuf[p] = '[') then
    Inc(p);
  for i := 1 to count do
  begin
    ParseNumber(p, v);
    arr[i] := v;
    SkipWs(p);
  end;
end;

procedure ParseBoolArray15(const key: string; var arr: VECTOR);
var
  pos, p, i: integer;
  b: boolean;
begin
  pos := FindKey(key, 1);
  if pos = 0 then
    Exit;
  p := pos;
  SkipWs(p);
  if (p <= Length(InputBuf)) and (InputBuf[p] = '[') then
    Inc(p);
  for i := 1 to NLIC do
  begin
    if not ParseBool(p, b) then
      b := false;
    arr[i] := b;
    SkipWs(p);
  end;
end;

procedure ParseLCM;
var
  pos, p, i, j: integer;
  tok: string;
begin
  pos := FindKey('lcm', 1);
  if pos = 0 then
    Exit;
  p := pos;
  SkipWs(p);
  if (p <= Length(InputBuf)) and (InputBuf[p] = '[') then
    Inc(p);
  for i := 1 to NLIC do
  begin
    SkipWs(p);
    if (p <= Length(InputBuf)) and (InputBuf[p] = '[') then
      Inc(p);
    for j := 1 to NLIC do
    begin
      ParseStringToken(p, tok);
      if tok = 'NOTUSED' then
        LCM[i, j] := NOTUSED
      else if tok = 'ORR' then
        LCM[i, j] := ORR
      else
        LCM[i, j] := ANDD;
      SkipWs(p);
    end;
    SkipWs(p);
    if (p <= Length(InputBuf)) and (InputBuf[p] = ']') then
      Inc(p);
    SkipWs(p);
  end;
end;

procedure ParseParameters;
var
  pos, p: integer;
  vi: integer;

  procedure Field(const name: string; var dest: real); overload;
  begin
    pos := FindKey(name, 1);
    if pos = 0 then
      Exit;
    p := pos;
    ParseNumber(p, dest);
  end;

  procedure FieldInt(const name: string; var dest: integer);
  begin
    pos := FindKey(name, 1);
    if pos = 0 then
      Exit;
    p := pos;
    ParseInt(p, dest);
  end;

begin
  Field('LENGTH1', PARAMETERS.LENGTH1);
  Field('RADIUS1', PARAMETERS.RADIUS1);
  Field('EPSILON', PARAMETERS.EPSILON);
  Field('AREA1', PARAMETERS.AREA1);
  FieldInt('Q_PTS', vi);
  PARAMETERS.Q_PTS := vi;
  FieldInt('QUADS', vi);
  PARAMETERS.QUADS := vi;
  Field('DIST', PARAMETERS.DIST);
  FieldInt('N_PTS', vi);
  PARAMETERS.N_PTS := vi;
  FieldInt('K_PTS', vi);
  PARAMETERS.K_PTS := vi;
  FieldInt('A_PTS', vi);
  PARAMETERS.A_PTS := vi;
  FieldInt('B_PTS', vi);
  PARAMETERS.B_PTS := vi;
  FieldInt('C_PTS', vi);
  PARAMETERS.C_PTS := vi;
  FieldInt('D_PTS', vi);
  PARAMETERS.D_PTS := vi;
  FieldInt('E_PTS', vi);
  PARAMETERS.E_PTS := vi;
  FieldInt('F_PTS', vi);
  PARAMETERS.F_PTS := vi;
  FieldInt('G_PTS', vi);
  PARAMETERS.G_PTS := vi;
  Field('LENGTH2', PARAMETERS.LENGTH2);
  Field('RADIUS2', PARAMETERS.RADIUS2);
  Field('AREA2', PARAMETERS.AREA2);
end;

procedure ReadInput;
var
  pos, p, np: integer;
  ch: char;
begin
  InputBuf := '';
  repeat
    Read(ch);
    if not Eof(Input) then
      InputBuf := InputBuf + ch;
  until Eof(Input);
  pos := FindKey('numpoints', 1);
  p := pos;
  ParseInt(p, np);
  NUMPOINTS := np;

  ParseRealArray('x', X, NUMPOINTS);
  ParseRealArray('y', Y, NUMPOINTS);
  ParseParameters;
  ParseLCM;
  ParseBoolArray15('pum_diag', CMV);
  for np := 1 to NLIC do
    PUM[np, np] := CMV[np];
end;

function BoolStr(b: boolean): string;
begin
  if b then
    BoolStr := 'true'
  else
    BoolStr := 'false';
end;

procedure WriteOutput;
var
  i, j: integer;
begin
  Write('{"cmv":[');
  for i := 1 to NLIC do
  begin
    if i > 1 then
      Write(',');
    Write(BoolStr(CMV[i]));
  end;
  Write('],"pum":[');
  for i := 1 to NLIC do
  begin
    if i > 1 then
      Write(',');
    Write('[');
    for j := 1 to NLIC do
    begin
      if j > 1 then
        Write(',');
      Write(BoolStr(PUM[i, j]));
    end;
    Write(']');
  end;
  Write('],"fuv":[');
  for i := 1 to NLIC do
  begin
    if i > 1 then
      Write(',');
    Write(BoolStr(FUV[i]));
  end;
  Write('],"launch":');
  Write(BoolStr(LAUNCH));
  WriteLn('}');
end;

begin
  ReadInput;
  DECIDE;
  WriteOutput;
end.
